import React, { useState } from "react";

const TENANT_API = "http://localhost:5003";

export default function TenantForm({ tenant, onSuccess }) {
  const [name, setName] = useState(tenant?.name || "");
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();

    if (!name.trim()) {
      alert("Tenant name is required");
      return;
    }

    try {
      setLoading(true);

      const isEdit = !!tenant;
      const url = isEdit
        ? `${TENANT_API}/tenants/${tenant.id}`
        : `${TENANT_API}/tenants`;

      const method = isEdit ? "PUT" : "POST";

      const res = await fetch(url, {
        method,
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({ name }),
      });

      if (!res.ok) {
        throw new Error("Failed to save tenant");
      }

      if (onSuccess) {
        onSuccess();
      }
    } catch (err) {
      console.error(err);
      alert("Failed to save tenant");
    } finally {
      setLoading(false);
    }
  };

  return (
    <form className="form-shell" onSubmit={handleSubmit}>
      <h2 className="form-title">{tenant ? "Edit Tenant" : "Create Tenant"}</h2>
      <p className="form-subtitle">Add or update a tenant in the platform.</p>

      <div className="form-group">
        <label className="form-label">Tenant Name</label>
        <input
          className="form-input"
          type="text"
          placeholder="Enter tenant name"
          value={name}
          onChange={(e) => setName(e.target.value)}
        />
      </div>

      <button className="btn btn-primary form-submit" type="submit" disabled={loading}>
        {loading ? "Saving..." : tenant ? "Update Tenant" : "Create Tenant"}
      </button>
    </form>
  );
}
